/**
 * mothertoken — benchmark data
 *
 * This file is baked into the Astro build at compile time.
 * It is generated by benchmark/run_benchmark.py and committed to the repo.
 * Raw FLORES+ sentences are never included here — only aggregated metrics.
 *
 * To regenerate:
 *   cd ../benchmark && python run_benchmark.py --output ../web/src/data/benchmark.json
 */

export interface ModelMetrics {
  cpt: number;   // chars per token — higher is better
  fert: number;  // fertility (tokens per word) — lower is better
}

export interface ModelData {
  name: string;
  metrics: Record<string, ModelMetrics>; // keyed by language id
}

export interface BenchmarkData {
  version: string;
  baseline: string;
  models: Record<string, ModelData>;
  languages: Record<string, { name: string; script: string }>;
}

